#include <stdio.h>

int main() {
    int N, index, element;

    scanf("%d", &N);
    int arr[101];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    scanf("%d", &index);
    scanf("%d", &element);

    for (int i = N; i > index; i--) {
        arr[i] = arr[i - 1];
    }
    arr[index] = element;

    for (int i = 0; i <= N; i++) {
        printf("%d", arr[i]);
        if (i < N) {
            printf(" ");
        }
    }
    printf("\n");

    return 0;
}
